'use client'
// src/components/Project.js
import React, { useRef, useState, useEffect } from 'react';
import './Project.css';

const projects = [
  {
    id: 1,
    title: 'TurboType',
    date: '2025-09',
    language: 'TypeScript',
    additionalTech: 'React, Node.js, PostgreSQL, Gemini API, Kotlin',
    github: 'https://github.com/csc301-2025-f/project-24-turbotype',
    projectLink: '',
    description: 'A full-stack collaborative typing practice platform built with a team using TypeScript, React, Node.js, and PostgreSQL. Features real-time feedback, performance tracking, and AI-generated practice sentences powered by the Gemini API. A companion Android app built in Kotlin extends the platform to mobile.',
    image: ''
  },
  {
    id: 2,
    title: 'Memory Care',
    date: '2026-01',
    language: 'Dart',
    additionalTech: 'Flutter, Firebase',
    github: 'https://github.com/oneDotpy/iteration-zero',
    projectLink: '',
    description: 'A research-based mobile app built with Flutter and Firebase to strengthen the connection between caregivers and memory-impaired patients. Features real-time data sync, secure authentication, and caregiver-focused features grounded in caregiving research.',
    image: ''
  },
  {
    id: 3,
    title: 'Caribou Quest',
    date: '2024-01',
    language: 'JavaScript',
    additionalTech: 'React Native, MongoDB, OpenAI API',
    github: '',
    projectLink: 'https://taikai.network/hackbox/hackathons/hawkhacks/projects/clwcyd8jy0cedyg01t0g2278n/idea',
    description: 'A gamified city exploration app with AI-driven recommendations for activities and local places. Built with React Native and MongoDB, integrating the OpenAI API for personalized suggestions and an image detection API with AR for interactive location-based tasks. Originally submitted at HawkHacks 2024.',
    image: 'https://ibb.co/nRg1FMj'
  },
  {
    id: 4,
    title: 'Partial Word Writer',
    date: '2025-09',
    language: 'Kotlin',
    additionalTech: 'Google Cloud, MongoDB',
    github: '',
    projectLink: '',
    description: 'An Android app built with Kotlin that predicts full words from partial inputs through sentence-level context modeling. Backend APIs are deployed on Google Cloud with MongoDB for low-latency prediction lookups.',
    image: ''
  },
  {
    id: 5,
    title: 'Be The Hacker',
    date: '2025-01',
    language: 'JavaScript',
    additionalTech: 'React, Firebase, OpenAI API',
    github: 'https://github.com/oneDotpy/BeTheHacker',
    projectLink: '',
    description: 'A gamified cybersecurity education platform built with React, Firebase, and the OpenAI API. Teaches users cybersecurity awareness through interactive, scenario-based challenges, with secure coding practices including authentication, access control, and safe data handling throughout.',
    image: ''
  },
  {
    id: 6,
    title: 'VentureBound',
    date: '2024-11',
    language: 'Java',
    additionalTech: 'Firebase, OpenAI API',
    github: 'https://github.com/oneDotpy/VentureBound',
    projectLink: '',
    description: 'A real-time group chat app built with Java and Firebase for collaborative trip planning. Features an AI assistant powered by the OpenAI API that gathers preferences and generates structured travel recommendations with error handling.',
    image: ''
  },
];

const Project = () => {
  const [sortOption, setSortOption] = useState('date');
  const [dateFilter, setDateFilter] = useState('latest');
  const [languageFilter, setLanguageFilter] = useState('');
  const [selectedProject, setSelectedProject] = useState(null);
  
  const [showLeftArrow, setShowLeftArrow] = useState(false);
  
  const carouselRef = useRef(null);

  const sortedProjects = [...projects]
    .filter((project) =>
      languageFilter ? project.language === languageFilter : true
    )
    .sort((a, b) => {
      const dateA = new Date(a.date.replace(/-/g, '/')); // Ensure cross-browser compatibility
      const dateB = new Date(b.date.replace(/-/g, '/'));
      if (dateFilter === 'earliest') return dateA - dateB;
      if (dateFilter === 'latest') return dateB - dateA;
      return 0;
    });

  const [showRightArrow, setShowRightArrow] = useState(sortedProjects.length > 1);

  const openModal = (project) => setSelectedProject(project);
  const closeModal = () => setSelectedProject(null);

  const handleNext = () => {
    carouselRef.current.scrollBy({ left: carouselRef.current.offsetWidth, behavior: 'smooth' });
  };

  const handlePrev = () => {
    carouselRef.current.scrollBy({ left: -carouselRef.current.offsetWidth, behavior: 'smooth' });
  };

  useEffect(() => {
    if (carouselRef.current) {
      carouselRef.current.scrollTo({ left: 0, behavior: 'smooth' });
    }
  }, [dateFilter]);  

  useEffect(() => {
    if (sortOption === 'date') {
      setLanguageFilter(''); // Reset language filter
    } else if (sortOption === 'language') {
      setDateFilter('latest'); // Reset date filter
    }
  }, [sortOption]);  

  useEffect(() => {
    const handleScroll = () => {
      const { scrollLeft, scrollWidth, clientWidth } = carouselRef.current;
      setShowLeftArrow(scrollLeft > 0);
      setShowRightArrow(scrollLeft + clientWidth < scrollWidth - 1);
    };
  
    const carousel = carouselRef.current;
  
    if (carousel) {
      carousel.addEventListener('scroll', handleScroll);
  
      // Initial check to set arrow visibility correctly
      handleScroll();
  
      return () => carousel.removeEventListener('scroll', handleScroll);
    }
  }, [sortedProjects]);  
  

  useEffect(() => {
    if (selectedProject) {
      document.body.classList.add('modal-open');
    } else {
      document.body.classList.remove('modal-open');
    }
  }, [selectedProject]);
  
  return (
    <div className="project-section" id="project">
      <h2>Projects</h2>

      <div className="filters">
        <select onChange={(e) => setSortOption(e.target.value)} value={sortOption}>
          <option value="date">Date</option>
          <option value="language">Language</option>
        </select>

        {sortOption === 'date' && (
          <select onChange={(e) => setDateFilter(e.target.value)} value={dateFilter}>
            <option value="earliest">By Earliest</option>
            <option value="latest">By Latest</option>
          </select>
        )}

        {sortOption === 'language' && (
          <select onChange={(e) => setLanguageFilter(e.target.value)} value={languageFilter}>
            <option value="">Select Language</option>
            {[...new Set(projects.map((p) => p.language))].map((language) => (
              <option key={language} value={language}>{language}</option>
            ))}
          </select>
        )}
      </div>

      <div className="carousel-container">
        {showLeftArrow && (
          <button className="arrow left-arrow" onClick={handlePrev}>
            &#8592;
          </button>
        )}

        <div className="project-cards" ref={carouselRef}>
          {sortedProjects.map((project) => (
            <div key={project.id} className="project-card" onClick={() => openModal(project)}>
              <h3>{project.title}</h3>
              <p className="card-date">{project.date}</p>
              <p className="card-tech">{project.language}{project.additionalTech ? ` · ${project.additionalTech}` : ''}</p>
            </div>
          ))}
        </div>

        {showRightArrow && (
          <button className="arrow right-arrow" onClick={handleNext}>
            &#8594;
          </button>
        )}
      </div>
      
      {sortedProjects.length > 1 ? (
        <div className="slide-hint">Swipe to explore more projects &rarr;</div>
      ) : null}


      {selectedProject && (
        <div className="modal">
          <div className="modal-content-wrapper">
            <button className="close-button" onClick={closeModal}>
              &times;
            </button>
            {selectedProject.image && (
              <img
                src={selectedProject.image}
                alt={selectedProject.title}
                className="modal-image"
              />
            )}
            <h2>{selectedProject.title}</h2>
            <p>{selectedProject.description}</p>
            <p>Date: {selectedProject.date}</p>
            <p>Language: {selectedProject.language}</p>
            {selectedProject.additionalTech && (
              <p>Additional Tech: {selectedProject.additionalTech}</p>
            )}
            <div className="modal-buttons">
              {selectedProject.github && (
                <a href={selectedProject.github} className="modal-button" target="_blank" rel="noopener noreferrer">
                  GitHub
                </a>
              )}
              {selectedProject.projectLink && (
                <a href={selectedProject.projectLink} className="modal-button" target="_blank" rel="noopener noreferrer">
                  Visit Project
                </a>
              )}
            </div>
          </div>
        </div>
      )}



    </div>
  );
};

export default Project;
